#include <time.h>

// تعريف دالة لاختبار الضغط الآمن
void test_pressure_safety() {
    // تحديد عدد مرات الضغط
    int num_presses = 10;

    // تحديد عدد مرات الضغط التي تمت بالفعل
    int num_presses_made = 0;

    // بدء التكرار
    while (num_presses_made < num_presses) {
        // سؤال المستخدم عن الضغط
        printf("هل تريد الضغط؟ (نعم/لا): ");
        char response[10];
        fgets(response, 10, stdin);

        // تحليل الإجابة
        if (strcmp(response, "نعم\n") == 0) {
            // زيادة عدد مرات الضغط
            num_presses_made++;
            printf("تم الضغط.\n");
        } else if (strcmp(response, "لا\n") == 0) {
            // إنهاء التكرار
            break;
        } else {
            // إعادة سؤال المستخدم
            printf("إجابة غير صحيحة. حاول مرة أخرى.\n");
        }

        // تأخير لمدة 2 ثواني
        sleep(2);
    }

    // إظهار النتيجة
    if (num_presses_made == num_presses) {
        printf("تم اختبار الضغط الآمن بنجاح.\n");
    } else {
        printf("لم يتم اختبار الضغط الآمن.\n");
    }
}

int main() {
    // بدء التوقيت
    time_t start_time = time(NULL);

    // بدء اختبار الضغط الآمن
    test_pressure_safety();

    // إظهار الوقت المستغرق
    time_t end_time = time(NULL);
    printf("الوقت المستغرق: %d ثانية\n", difftime(end_time, start_time));

    return 0;
}
